import { createArrowNav, type ArrowNav } from '@o9ds/core';
import { O9Button, type O9ButtonOptions } from '../Button/Button';
import { O9IconButton, type O9IconButtonOptions } from '../IconButton/IconButton';

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface ButtonGroupItem {
  value: string;
  label?: string;
  icon?: string;
  isDisabled?: boolean;
  isExcluded?: boolean;
}

export interface O9ButtonGroupOptions {
  items?: ButtonGroupItem[];
  value?: string | string[] | null;
  variant?: 'primary' | 'secondary';
  size?: 'sm' | 'lg';
  isMultiSelect?: boolean;
  isIconOnly?: boolean;
  hasOverflow?: boolean;
  expandOnSelect?: boolean;
  isDisabled?: boolean;
  isLoading?: boolean;
  ariaLabel: string;
  onChange?: (detail: ButtonGroupChangeDetail) => void;
}

export interface ButtonGroupChangeDetail {
  value: string | string[] | null;
  previousValue: string | string[] | null;
  changedValue?: string;
  isSelected?: boolean;
  [key: string]: unknown;
}

type RequiredGroupOptions = Required<
  Omit<O9ButtonGroupOptions, 'onChange' | 'items' | 'value'>
> & {
  items: ButtonGroupItem[];
  value: string | string[] | null;
  onChange: ((detail: ButtonGroupChangeDetail) => void) | null;
};

// ---------------------------------------------------------------------------
// Class
// ---------------------------------------------------------------------------

export class O9ButtonGroup {
  private _element: HTMLElement | null;
  private _options: RequiredGroupOptions;

  private _childButtons: (O9Button | O9IconButton)[] = [];
  private _childElements: HTMLButtonElement[] = [];
  private _overflowTrigger: O9IconButton | null = null;
  private _overflowTriggerEl: HTMLButtonElement | null = null;
  private _overflowMenuEl: HTMLDivElement | null = null;

  private _arrowNav: ArrowNav | null = null;
  private _resizeObserver: ResizeObserver | null = null;
  private _hiddenIndices: Set<number> = new Set();

  private _boundHandleKeydown: (event: KeyboardEvent) => void;
  private _boundHandleClick: (event: Event) => void;
  private _boundHandleOverflowClick: (event: Event) => void;
  private _boundCloseOverflowMenu: (event: Event) => void;

  static readonly VARIANTS = ['primary', 'secondary'] as const;
  static readonly SIZES = ['sm', 'lg'] as const;

  static readonly DEFAULTS: RequiredGroupOptions = {
    items: [],
    value: null,
    variant: 'primary',
    size: 'lg',
    isMultiSelect: false,
    isIconOnly: false,
    hasOverflow: false,
    expandOnSelect: false,
    isDisabled: false,
    isLoading: false,
    ariaLabel: '',
    onChange: null,
  };

  static initialize(element: HTMLElement, options?: O9ButtonGroupOptions): O9ButtonGroup {
    return new O9ButtonGroup(element, options);
  }

  constructor(element: HTMLElement, options?: O9ButtonGroupOptions) {
    this._element = element;

    const variant = options?.variant && (O9ButtonGroup.VARIANTS as readonly string[]).includes(options.variant)
      ? options.variant
      : O9ButtonGroup.DEFAULTS.variant;

    const size = options?.size && (O9ButtonGroup.SIZES as readonly string[]).includes(options.size)
      ? options.size
      : O9ButtonGroup.DEFAULTS.size;

    this._options = {
      ...O9ButtonGroup.DEFAULTS,
      ...options,
      variant,
      size,
      items: options?.items ?? [],
      value: options?.value ?? null,
      onChange: options?.onChange ?? null,
    };

    if (this._options.isMultiSelect) {
      this._options.expandOnSelect = false;
    }

    this._boundHandleKeydown = this._handleKeydown.bind(this);
    this._boundHandleClick = this._handleClick.bind(this);
    this._boundHandleOverflowClick = this._handleOverflowClick.bind(this);
    this._boundCloseOverflowMenu = this._closeOverflowMenu.bind(this);

    this._render();
    this._bindEvents();
  }

  // ── Render ─────────────────────────────────────────────────────────────

  private _render(): void {
    const el = this._element;
    if (!el) return;

    el.textContent = '';
    this._childButtons = [];
    this._childElements = [];
    this._hiddenIndices = new Set();

    const {
      items, value: _value, variant: _variant, size, isMultiSelect: _multiSelect, isIconOnly,
      hasOverflow, expandOnSelect, isDisabled, isLoading, ariaLabel,
    } = this._options;

    el.className = this._buildRootClasses();
    el.setAttribute('role', 'toolbar');
    el.setAttribute('aria-orientation', 'horizontal');
    el.setAttribute('aria-label', ariaLabel);
    if (isLoading) el.setAttribute('aria-busy', 'true');

    const buttonSize = size === 'sm' ? 'sm' : 'md';

    for (const item of items) {
      const btnEl = document.createElement('button');
      el.appendChild(btnEl);
      this._childElements.push(btnEl);

      const isActive = this._isItemActive(item.value);
      const isItemDisabled = isDisabled || (item.isDisabled ?? false);
      const useIconOnly = isIconOnly || (expandOnSelect && !isActive && !!item.icon);

      let instance: O9Button | O9IconButton;

      if (useIconOnly || (!item.label && item.icon)) {
        instance = O9IconButton.initialize(btnEl, {
          icon: item.icon ?? '',
          tooltip: item.label ?? item.value,
          variant: 'tertiary',
          size: buttonSize,
          isDisabled: isItemDisabled,
          isLoading: isLoading && !(item.isExcluded ?? false),
          isSelected: isActive,
        } as O9IconButtonOptions);
      } else {
        instance = O9Button.initialize(btnEl, {
          label: item.label ?? item.value,
          icon: item.icon ?? null,
          variant: 'tertiary',
          size: buttonSize,
          isDisabled: isItemDisabled,
          isLoading: isLoading && !(item.isExcluded ?? false),
          isSelected: isActive,
        } as O9ButtonOptions);
      }

      btnEl.setAttribute('data-value', item.value);
      this._childButtons.push(instance);
    }

    if (hasOverflow) {
      this._overflowTriggerEl = document.createElement('button');
      el.appendChild(this._overflowTriggerEl);
      this._overflowTriggerEl.className = 'o9ds-btn-grp__overflow';
      this._overflowTriggerEl.style.display = 'none';

      this._overflowTrigger = O9IconButton.initialize(this._overflowTriggerEl, {
        icon: 'ellipsis-v',
        tooltip: 'More actions',
        variant: 'tertiary',
        size: buttonSize,
        isDisabled,
      } as O9IconButtonOptions);

      this._overflowTriggerEl.setAttribute('aria-haspopup', 'menu');
      this._overflowTriggerEl.setAttribute('aria-expanded', 'false');
    }

    this._syncRovingTabindex();
    this._setupArrowNav();

    if (hasOverflow) {
      this._setupResizeObserver();
    }
  }

  private _buildRootClasses(): string {
    const { variant, size, isMultiSelect, isIconOnly, hasOverflow, expandOnSelect, isDisabled, isLoading } = this._options;
    return [
      'o9ds-btn-grp',
      `o9ds-btn-grp--${variant}`,
      `o9ds-btn-grp--${size}`,
      isMultiSelect && 'o9ds-btn-grp--multi',
      isIconOnly && 'o9ds-btn-grp--icon-only',
      hasOverflow && 'o9ds-btn-grp--overflow',
      expandOnSelect && !isMultiSelect && 'o9ds-btn-grp--expand-lbl',
      isDisabled && 'is-disabled',
      isLoading && 'loading',
    ].filter(Boolean).join(' ');
  }

  // ── Events ─────────────────────────────────────────────────────────────

  private _bindEvents(): void {
    this._element?.addEventListener('keydown', this._boundHandleKeydown);
    this._element?.addEventListener('click', this._boundHandleClick);
  }

  private _handleKeydown(event: KeyboardEvent): void {
    if (this._options.isDisabled || this._options.isLoading) return;
    this._arrowNav?.handleKeyDown(event);
  }

  private _handleClick(event: Event): void {
    if (this._options.isDisabled || this._options.isLoading) return;

    const target = event.target as HTMLElement;
    const btnEl = target.closest('button[data-value]') as HTMLButtonElement | null;
    if (!btnEl) return;

    const itemValue = btnEl.getAttribute('data-value');
    if (!itemValue) return;

    const item = this._options.items.find(i => i.value === itemValue);
    if (!item || item.isDisabled || this._options.isDisabled) return;

    if (this._options.isMultiSelect) {
      this._toggleMulti(itemValue);
    } else {
      this._selectSingle(itemValue);
    }
  }

  private _selectSingle(newValue: string): void {
    const previousValue = this._options.value as string | null;
    if (previousValue === newValue) return;

    this._options.value = newValue;
    this._syncActiveStates();
    this._syncRovingTabindex();

    if (this._options.expandOnSelect) {
      this._syncExpandLabels();
    }

    const detail: ButtonGroupChangeDetail = { value: newValue, previousValue };
    this._dispatchEvent('btn-grp:change', detail);
    this._options.onChange?.(detail);
  }

  private _toggleMulti(itemValue: string): void {
    const currentValues = (this._options.value as string[] | null) ?? [];
    const previousValue = [...currentValues];
    const idx = currentValues.indexOf(itemValue);
    const isSelected = idx === -1;

    if (isSelected) {
      currentValues.push(itemValue);
    } else {
      currentValues.splice(idx, 1);
    }

    this._options.value = [...currentValues];
    this._syncActiveStates();
    this._syncRovingTabindex();

    const detail: ButtonGroupChangeDetail = {
      value: [...currentValues],
      previousValue,
      changedValue: itemValue,
      isSelected,
    };
    this._dispatchEvent('btn-grp:change', detail);
    this._options.onChange?.(detail);
  }

  // ── State sync ─────────────────────────────────────────────────────────

  private _isItemActive(itemValue: string): boolean {
    const { value, isMultiSelect } = this._options;
    if (isMultiSelect) {
      return Array.isArray(value) && value.includes(itemValue);
    }
    return value === itemValue;
  }

  private _syncActiveStates(): void {
    const { items } = this._options;
    for (let i = 0; i < items.length; i++) {
      const isActive = this._isItemActive(items[i].value);
      const btn = this._childButtons[i];
      if (btn) {
        btn.selected(isActive);
      }
    }
  }

  private _syncExpandLabels(): void {
    if (!this._options.expandOnSelect || this._options.isMultiSelect) return;

    const { items } = this._options;
    const el = this._element;
    if (!el) return;

    for (let i = 0; i < items.length; i++) {
      const item = items[i];
      const btnEl = this._childElements[i];
      if (!btnEl || !item.icon) continue;

      const isActive = this._isItemActive(item.value);
      const oldBtn = this._childButtons[i];
      if (oldBtn) oldBtn.destroy();

      const buttonSize = this._options.size === 'sm' ? 'sm' : 'md';
      const isDisabled = this._options.isDisabled || (item.isDisabled ?? false);
      const isLoading = this._options.isLoading && !(item.isExcluded ?? false);

      if (!isActive || !item.label) {
        const newInst = O9IconButton.initialize(btnEl, {
          icon: item.icon,
          tooltip: item.label ?? item.value,
          variant: 'tertiary',
          size: buttonSize,
          isDisabled: isDisabled,
          isLoading: isLoading,
          isSelected: isActive,
        } as O9IconButtonOptions);
        this._childButtons[i] = newInst;
      } else {
        const newInst = O9Button.initialize(btnEl, {
          label: item.label,
          icon: item.icon,
          variant: 'tertiary',
          size: buttonSize,
          isDisabled: isDisabled,
          isLoading: isLoading,
          isSelected: isActive,
        } as O9ButtonOptions);
        this._childButtons[i] = newInst;
      }
      btnEl.setAttribute('data-value', item.value);
    }

    this._syncRovingTabindex();
    this._setupArrowNav();
  }

  private _syncRovingTabindex(): void {
    const { items, value, isMultiSelect } = this._options;
    let selectedIdx = -1;
    let firstEnabledIdx = -1;

    for (let i = 0; i < items.length; i++) {
      if (this._hiddenIndices.has(i)) continue;
      const isEnabled = !items[i].isDisabled && !this._options.isDisabled;
      if (isEnabled && firstEnabledIdx === -1) firstEnabledIdx = i;

      if (!isMultiSelect && value === items[i].value && isEnabled) {
        selectedIdx = i;
      } else if (isMultiSelect && Array.isArray(value) && value.includes(items[i].value) && isEnabled) {
        if (selectedIdx === -1) selectedIdx = i;
      }
    }

    const activeIdx = selectedIdx !== -1 ? selectedIdx : firstEnabledIdx;

    for (let i = 0; i < this._childElements.length; i++) {
      this._childElements[i].tabIndex = i === activeIdx ? 0 : -1;
    }
  }

  // ── Arrow Nav ──────────────────────────────────────────────────────────

  private _setupArrowNav(): void {
    this._arrowNav?.destroy();

    const enabledElements = this._childElements.filter((el, i) => {
      const item = this._options.items[i];
      return !item?.isDisabled && !this._options.isDisabled && !this._hiddenIndices.has(i);
    });

    if (enabledElements.length === 0) {
      this._arrowNav = null;
      return;
    }

    const { isMultiSelect } = this._options;

    this._arrowNav = createArrowNav({
      items: enabledElements,
      orientation: 'horizontal',
      wrap: true,
      onNavigate: (item: HTMLElement, _index: number) => {
        for (const el of this._childElements) {
          el.tabIndex = -1;
        }
        (item as HTMLButtonElement).tabIndex = 0;
        (item as HTMLButtonElement).focus();

        if (!isMultiSelect) {
          const val = item.getAttribute('data-value');
          if (val) this._selectSingle(val);
        }
      },
      onSelect: (item: HTMLElement) => {
        const val = item.getAttribute('data-value');
        if (!val) return;
        if (isMultiSelect) {
          this._toggleMulti(val);
        } else {
          this._selectSingle(val);
        }
      },
    });
  }

  // ── Overflow ───────────────────────────────────────────────────────────

  private _setupResizeObserver(): void {
    if (!this._element || !this._options.hasOverflow) return;

    this._resizeObserver = new ResizeObserver(() => {
      this._checkOverflow();
    });
    this._resizeObserver.observe(this._element);
    this._checkOverflow();
  }

  private _checkOverflow(): void {
    const el = this._element;
    if (!el) return;

    const containerRect = el.getBoundingClientRect();
    const triggerWidth = this._overflowTriggerEl?.offsetWidth ?? 0;
    const availableWidth = containerRect.width - triggerWidth;

    this._hiddenIndices.clear();

    for (let i = 0; i < this._childElements.length; i++) {
      const btnEl = this._childElements[i];
      const btnRect = btnEl.getBoundingClientRect();
      const isClipped = btnRect.right > containerRect.left + availableWidth;

      if (isClipped) {
        this._hiddenIndices.add(i);
        btnEl.style.visibility = 'hidden';
        btnEl.style.position = 'absolute';
        btnEl.style.pointerEvents = 'none';
        btnEl.tabIndex = -1;
      } else {
        btnEl.style.visibility = '';
        btnEl.style.position = '';
        btnEl.style.pointerEvents = '';
      }
    }

    if (this._overflowTriggerEl) {
      const hasHidden = this._hiddenIndices.size > 0;
      this._overflowTriggerEl.style.display = hasHidden ? '' : 'none';
      if (hasHidden) {
        this._overflowTriggerEl.removeAttribute('aria-hidden');
      } else {
        this._overflowTriggerEl.setAttribute('aria-hidden', 'true');
      }
    }

    this._syncRovingTabindex();
    this._setupArrowNav();
  }

  private _handleOverflowClick(_event: Event): void {
    if (this._overflowMenuEl) {
      this._closeOverflowMenu();
      return;
    }
    this._openOverflowMenu();
  }

  private _overflowMenuButtons: O9Button[] = [];

  private _openOverflowMenu(): void {
    if (!this._overflowTriggerEl || this._hiddenIndices.size === 0) return;

    this._overflowMenuEl = document.createElement('div');
    this._overflowMenuEl.className = 'o9ds-btn-grp__overflow-menu';
    this._overflowMenuEl.setAttribute('role', 'menu');

    const buttonSize = this._options.size === 'sm' ? 'sm' : 'md';

    for (const idx of this._hiddenIndices) {
      const item = this._options.items[idx];
      if (!item) continue;

      const menuBtnEl = document.createElement('button');
      menuBtnEl.setAttribute('role', 'menuitem');
      menuBtnEl.setAttribute('data-value', item.value);

      const isActive = this._isItemActive(item.value);
      const menuBtn = O9Button.initialize(menuBtnEl, {
        label: item.label ?? item.value,
        icon: item.icon ?? null,
        variant: 'tertiary',
        size: buttonSize,
        isDisabled: item.isDisabled ?? false,
        isSelected: isActive,
      } as O9ButtonOptions);

      this._overflowMenuButtons.push(menuBtn);

      menuBtnEl.addEventListener('click', () => {
        if (item.isDisabled) return;
        if (this._options.isMultiSelect) {
          this._toggleMulti(item.value);
        } else {
          this._selectSingle(item.value);
        }
        this._closeOverflowMenu();
      });

      this._overflowMenuEl.appendChild(menuBtnEl);
    }

    this._element?.appendChild(this._overflowMenuEl);
    this._overflowTriggerEl.setAttribute('aria-expanded', 'true');

    setTimeout(() => {
      document.addEventListener('click', this._boundCloseOverflowMenu);
    }, 0);
  }

  private _closeOverflowMenu(event?: Event): void {
    if (event && this._overflowMenuEl?.contains(event.target as Node)) return;
    if (event && this._overflowTriggerEl?.contains(event.target as Node)) return;

    for (const btn of this._overflowMenuButtons) {
      btn.destroy();
    }
    this._overflowMenuButtons = [];

    this._overflowMenuEl?.remove();
    this._overflowMenuEl = null;
    this._overflowTriggerEl?.setAttribute('aria-expanded', 'false');
    document.removeEventListener('click', this._boundCloseOverflowMenu);
  }

  private _dispatchEvent(eventName: string, detail: Record<string, unknown>): void {
    this._element?.dispatchEvent(
      new CustomEvent(eventName, { bubbles: true, cancelable: true, detail })
    );
  }

  // ── Public API ─────────────────────────────────────────────────────────

  value(): string | string[] | null;
  value(newValue: string | string[] | null): void;
  value(newValue?: string | string[] | null): string | string[] | null | void {
    if (newValue === undefined) return this._options.value;

    if (!this._element) return;

    const previousValue = this._options.value;
    this._options.value = newValue;
    this._syncActiveStates();
    this._syncRovingTabindex();

    if (this._options.expandOnSelect && !this._options.isMultiSelect) {
      this._syncExpandLabels();
    }

    const detail: ButtonGroupChangeDetail = {
      value: newValue,
      previousValue,
    };
    this._dispatchEvent('btn-grp:change', detail);
    this._options.onChange?.(detail);
  }

  disabled(): boolean;
  disabled(state: boolean): void;
  disabled(state?: boolean): boolean | void {
    if (state === undefined) return this._options.isDisabled;

    if (!this._element) return;
    this._options.isDisabled = state;
    this._element.classList.toggle('is-disabled', state);

    for (const btn of this._childButtons) {
      btn.disabled(state);
    }
    this._overflowTrigger?.disabled(state);
  }

  setVariant(variant: string): void {
    if (!(O9ButtonGroup.VARIANTS as readonly string[]).includes(variant)) return;

    const el = this._element;
    if (!el) return;

    O9ButtonGroup.VARIANTS.forEach(v => el.classList.remove(`o9ds-btn-grp--${v}`));
    el.classList.add(`o9ds-btn-grp--${variant}`);
    this._options.variant = variant as RequiredGroupOptions['variant'];
  }

  setLoading(isLoading: boolean): void {
    if (!this._element) return;
    this._options.isLoading = isLoading;
    this._element.classList.toggle('loading', isLoading);

    if (isLoading) {
      this._element.setAttribute('aria-busy', 'true');
    } else {
      this._element.removeAttribute('aria-busy');
    }

    for (let i = 0; i < this._childButtons.length; i++) {
      const item = this._options.items[i];
      if (item?.isExcluded) continue;
      this._childButtons[i].setLoading(isLoading);
    }

    this._overflowTrigger?.setLoading(isLoading);
  }

  setItems(items: ButtonGroupItem[]): void {
    if (!this._element) return;

    this._element.removeEventListener('keydown', this._boundHandleKeydown);
    this._element.removeEventListener('click', this._boundHandleClick);

    this._options.items = items;
    this._options.value = this._options.isMultiSelect ? [] : null;
    this._destroyChildren();
    this._render();
    this._bindEvents();
  }

  focus(): void {
    const selectedIdx = this._childElements.findIndex(el => el.tabIndex === 0);
    if (selectedIdx !== -1) {
      this._childElements[selectedIdx].focus();
    }
  }

  destroy(): void {
    this._arrowNav?.destroy();
    this._arrowNav = null;

    this._resizeObserver?.disconnect();
    this._resizeObserver = null;

    this._closeOverflowMenu();
    document.removeEventListener('click', this._boundCloseOverflowMenu);

    this._destroyChildren();

    if (this._overflowTrigger) {
      this._overflowTrigger.destroy();
      this._overflowTrigger = null;
      this._overflowTriggerEl = null;
    }

    if (this._element) {
      this._element.removeEventListener('keydown', this._boundHandleKeydown);
      this._element.removeEventListener('click', this._boundHandleClick);

      this._element.textContent = '';
      this._element.removeAttribute('role');
      this._element.removeAttribute('aria-orientation');
      this._element.removeAttribute('aria-label');
      this._element.removeAttribute('aria-busy');
      this._element.className = '';
    }

    this._element = null;
  }

  private _destroyChildren(): void {
    for (const btn of this._childButtons) {
      btn.destroy();
    }
    this._childButtons = [];
    this._childElements = [];
  }
}
